SELECT material_id, material_name
FROM materials
WHERE si > 80;

SELECT mc.composition_id, mc.version_id, mc.element_id, mc.percentage, mc.tolerance
FROM material_compositions mc
WHERE mc.percentage BETWEEN 'LowerBound' AND 'UpperBound';

SELECT COUNT(note_id) AS note_count
FROM material_notes
WHERE material_id = 1;

SELECT mc.*, e.element_name
FROM material_compositions mc
INNER JOIN elements e ON mc.element_id = e.element_id;

SELECT mn.note_date, mn.note_text
FROM material_notes mn
WHERE mn.material_id = 'Material_id';

SELECT DISTINCT m.material_name
FROM materials m
JOIN material_notes mn ON m.material_id = mn.material_id;

SELECT m.category, COUNT(m.material_id) AS number_of_materials
FROM materials m
GROUP BY m.category;
